	//
	// Default: 1000
	QueryLogSize *int32

	// Specifies the interval at which data replication occurs between cluster nodes.
	//
	// Default: 250ms
	ReplicationInterval *Duration

	// The interval at which retention policies are checked and enforced. Enter as a
